(()=>{var t=document.querySelector(".details"),c=t.querySelector("#expandAll"),s=t.querySelector("#collapseAll"),l=t.querySelectorAll("details");c.addEventListener("click",()=>{l.forEach(e=>e.open=!0)});s.addEventListener("click",()=>{l.forEach(e=>e.open=!1)});l.forEach(e=>{e.addEventListener("toggle",()=>{let n=e.open?`#${e.id}`:"#";history.pushState(null,null,n)})});var o=window.location.hash.slice(1);if(o){let e=t.querySelector(`#${CSS.escape(o)}`);e&&(e.open=!0)}})();

  (()=>{document.addEventListener("DOMContentLoaded",()=>{let r=document.querySelectorAll("[data-tab-target]"),d=document.querySelectorAll("[data-tab-panel]");d.forEach((e,t)=>{e.hidden=t!==0}),r.forEach((e,t)=>{e.setAttribute("aria-selected",t===0?"true":"false"),e.addEventListener("click",()=>{let c=e.dataset.tabTarget;r.forEach(a=>a.setAttribute("aria-selected","false")),d.forEach(a=>a.hidden=!0),e.setAttribute("aria-selected","true");let n=document.querySelector(`[data-tab-panel="${c}"]`);n&&(n.hidden=!1)})})});})();